## Proto Definitions

### EmbeddingService

```protobuf
syntax = "proto3";
package corvia.inference.v1;

service EmbeddingService {
  rpc Embed(EmbedRequest) returns (EmbedResponse);
  rpc EmbedBatch(EmbedBatchRequest) returns (EmbedBatchResponse);
  rpc ModelInfo(ModelInfoRequest) returns (ModelInfoResponse);
}

message EmbedRequest {
  string model = 1;
  string text = 2;
}

message EmbedResponse {
  repeated float embedding = 1 [packed = true];
  uint32 dimensions = 2;
}

message EmbedBatchRequest {
  string model = 1;
  repeated string texts = 2;
}

message EmbedBatchResponse {
  repeated Embedding embeddings = 1;
}

message Embedding {
  repeated float values = 1 [packed = true];
  uint32 index = 2;
}

message ModelInfoRequest {
  string model = 1;
}

message ModelInfoResponse {
  string model = 1;
  uint32 dimensions = 2;
  bool loaded = 3;
}
```


### ChatService

```protobuf
service ChatService {
  rpc Chat(ChatRequest) returns (ChatResponse);
  rpc ChatStream(ChatRequest) returns (stream ChatChunk);
}

message ChatMessage {
  string role = 1;
  string content = 2;
}

message ChatRequest {
  string model = 1;
  repeated ChatMessage messages = 2;
  float temperature = 3;
  uint32 max_tokens = 4;
}

message ChatResponse {
  ChatMessage message = 1;
  uint32 prompt_tokens = 2;
  uint32 completion_tokens = 3;
}

message ChatChunk {
  string delta = 1;
  bool done = 2;
  uint32 prompt_tokens = 3;
  uint32 completion_tokens = 4;
}
```
